build for javascript backend
database is local memory

create a Counter table:
  value, default 0

when user calls GET /api/count:
  all_counters = get all Counter
  if length of all_counters is 0:
    new_counter = save { value: 0 } to Counter
    send back { count: 0 }
  else:
    saved_counter = first of all_counters
    send back { count: saved_counter's value }

  all_counters = get all Counter
  all_counters = look up all Counter
  if length of all_counters is 0:
    saved_counter's value = next_value
    send back { count: 1 }
  else:
    saved_counter = first of all_counters
    next_value = saved_counter's value + 1
    saved_counter's value is next_value
    save saved_counter to Counter
    send back { count: next_value }

when user calls POST /api/reset:
  all_counters = get all Counter
  if length of all_counters is 0:
    new_counter = save { value: 0 } to Counter
  else:
    saved_counter = first of all_counters
    saved_counter's value = 0
    save saved_counter to Counter
  send back { count: 0 }
